    priority_level: getPriorityLevel(ticketData.priority),
    needs_attention: checkNeedsAttention(ticketData, now, createdAt),
    description: ticketData.description || "No Description"
  };
}

// Helper function to get priority level
function getPriorityLevel(priority) {
  const levels = {
    'low': 1,
    'normal': 2,
    'high': 3,
    'urgent': 4
  };
  return levels[priority] || 2;
}

