// Split by comma
const parts = cleaned.split(',').map(p => p.trim());

// Assign values even if missing
const videoPrompt = parts[0] || "";
const captionIdea = parts[1] || "";
const musicStyle = parts[2] || "";

return [
  {
    json: {
      videoPrompt,
      captionIdea,
      musicStyle
    }
  }
];

